  series: [
    { 
      name: 'CPU', 
      type: 'line', 
      data: cpuData.value, 
      smooth: true,
      areaStyle: {}
    },
    { 
      name: '内存', 
      type: 'line', 
      data: memoryData.value, 
      smooth: true,
      areaStyle: {}
    }
  ]
}

onMounted(() => {
  chart = echarts.init(chartRef.value!)
  chart.setOption(option)

  // 监听系统指标事件
  wsStore.on('system.metrics', (data) => {
    const now = new Date().toLocaleTimeString()

    timestamps.value.push(now)
    cpuData.value.push(data.cpu)
    memoryData.value.push(data.memory)

    // 保持最近 60 个数据点
    if (timestamps.value.length > 60) {
      timestamps.value.shift()
      cpuData.value.shift()
      memoryData.value.shift()
    }

    chart.setOption({
      xAxis: { data: timestamps.value },
      series: [
        { data: cpuData.value },
        { data: memoryData.value }
      ]
    })
  })

  // 响应式调整
  window.addEventListener('resize', () => chart.resize())
})

onUnmounted(() => {
  chart.dispose()
  window.removeEventListener('resize', () => chart.resize())
})
</script>
