    // 创建 Mock WebSocket 服务器
    mockServer = new MockWebSocketServer('ws://localhost:9999')
    wsManager = new WebSocketManager('ws://localhost:9999')
  })

  afterEach(() => {
    wsManager.disconnect()
    mockServer.close()
  })

  it('should connect to server', async () => {
    wsManager.connect()

    await vi.waitFor(() => {
      expect(wsManager.state.connected).toBe(true)
    }, { timeout: 3000 })
  })

  it('should receive messages from server', async () => {
    wsManager.connect()

    const callback = vi.fn()
    wsManager.on('test.event', callback)

