    await vi.waitFor(() => {
      expect(callback).toHaveBeenCalledWith({ message: 'hello' })
    })
  })

  it('should auto reconnect on disconnect', async () => {
    wsManager.connect()

    await vi.waitFor(() => {
      expect(wsManager.state.connected).toBe(true)
    })

    mockServer.disconnect()

    await vi.waitFor(() => {
      expect(wsManager.state.connectionState).toBe('reconnecting')
    })
  })
